#include "keypad_lock.h"
#include <Arduino.h>
#define LOCK_PIN 25
static bool _locked=true;static String _code;static unsigned long _unlockAt=0;
void lock_setup(const char*c){_code=String(c);pinMode(LOCK_PIN,OUTPUT);digitalWrite(LOCK_PIN,HIGH);Serial.println("[lock] OK");}
void lock_loop(){if(!_locked&&millis()>=_unlockAt){lock_lock();}}
void lock_unlock(uint16_t s){digitalWrite(LOCK_PIN,LOW);_locked=false;_unlockAt=millis()+s*1000UL;Serial.println("[lock] UNLOCKED");}
void lock_lock(){digitalWrite(LOCK_PIN,HIGH);_locked=true;Serial.println("[lock] LOCKED");}
bool lock_is_locked(){return _locked;}
